"use client";
import React from "react";

import CreditCard from "@mui/icons-material/CreditCard";
import Box from "@mui/material/Box";
import Container from "@mui/material/Container";
import CssBaseline from "@mui/material/CssBaseline";
import Fab from "@mui/material/Fab";
import { ThemeProvider, styled } from "@mui/material/styles";

import {
  Content,
  EdgeDrawerTriggerRight,
  EdgeSidebarContent,
  EdgeSidebarRight,
  Footer,
  Header,
  InsetAvoidingView,
  InsetContent,
  InsetSidebar,
  Root,
} from "../layout-core";
import {
  DailyCart,
  DailyCheckout,
  DailyHeader,
  DailySummary,
  dailyShoppingTheme,
} from "./components";

const StyledHeader = styled(Header)(() => ({
  backgroundColor: "#ffffff",
}));

const InsetAvoidingViewFooter = styled(InsetAvoidingView)(
  ({ theme: { breakpoints } }) => ({
    border: "unset",
    position: "relative",
    backgroundColor: "#fff",
    paddingTop: "1rem",

    "&:before": {
      content: '" "',
      position: "absolute",
      width: "100%",
      height: 24,
      top: -1,
      left: 0,
      transform: "translateY(-100%)",
      background: "linear-gradient(to top, #ffffff, rgba(255,255,255,0))",
    },

    [breakpoints.only("sm")]: {
      paddingRight: 64,
    },

    [breakpoints.up("md")]: {
      paddingBottom: 40,
    },
  }),
);

export function LayoutV6AppShoppingCart() {
  return (
    <ThemeProvider theme={dailyShoppingTheme}>
      <Root standalone>
        <CssBaseline />
        <EdgeDrawerTriggerRight
          render={
            <Fab
              color={"primary"}
              sx={(theme) => ({
                position: "fixed",
                bottom: 16,
                right: 16,
                color: "#2E3B4D",
                "& svg": {
                  fontSize: 32,
                  color: "#fff",
                },
                zIndex: 1500,
                transition: "0.3s cubic-bezier(.47,1.64,.41,.8)",
                [theme.breakpoints.up("sm")]: {
                  bottom: 40,
                },
                [theme.breakpoints.up("lg")]: {
                  transform: "scale(0)",
                },
              })}
            >
              <CreditCard />
            </Fab>
          }
        />
        <StyledHeader height="64px" sx={{ position: "relative" }}>
          <Container maxWidth="xl">
            <DailyHeader />
          </Container>
        </StyledHeader>
        <EdgeSidebarRight
          variant={{
            xs: ["drawer", { width: "min(400px, 100vw)" }],
          }}
        >
          <EdgeSidebarContent
            sx={{
              padding: "calc(var(--jun-ES-drawerOpen) * 0.5rem)",
              bgcolor: "initial",
            }}
          >
            <DailyCheckout />
          </EdgeSidebarContent>
        </EdgeSidebarRight>
        <Content>
          <Container maxWidth="xl">
            <DailyCart />
            <InsetSidebar
              position="absolute"
              width={{ lg: "max(25cqw, 360px)" }}
              sx={{
                "& > div": {
                  border: "none",
                  py: "1rem",
                },
              }}
            >
              <InsetContent>
                <DailyCheckout />
              </InsetContent>
            </InsetSidebar>
          </Container>
        </Content>
        <Footer>
          <Container maxWidth="xl">
            <InsetAvoidingViewFooter>
              <Box pb={3}>
                <DailySummary />
              </Box>
            </InsetAvoidingViewFooter>
          </Container>
        </Footer>
      </Root>
    </ThemeProvider>
  );
}

"use client";
import React from "react";
import { styled } from "@mui/material/styles";
import Box from "@mui/material/Box";
import Typography from "@mui/material/Typography";
import Table from "@mui/material/Table";
import TableBody from "@mui/material/TableBody";
import TableCell from "@mui/material/TableCell";
import TableContainer from "@mui/material/TableContainer";
import TableHead from "@mui/material/TableHead";
import TableRow from "@mui/material/TableRow";
import IconButton from "@mui/material/IconButton";
import Close from "@mui/icons-material/Close";
import DailySizeSelector from "./DailySizeSelector";
import DailyInteger from "./DailyInteger";

const TypographyHeading = styled(Typography)(({ theme: { breakpoints } }) => ({
  fontWeight: 900,
  fontSize: "1.75rem",
  textAlign: "center",

  [breakpoints.up("sm")]: {
    textAlign: "left",
  },

  [breakpoints.up("md")]: {
    fontSize: "2.25rem",
  },
}));

const StyledTable = styled(Table)(() => ({
  minWidth: 650,
}));

const ImgImage = styled("img")(() => ({
  width: "100%",
  height: "100%",
  objectFit: "contain",
}));

const PName = styled("p")(() => ({
  fontFamily:
    "-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,Oxygen,Ubuntu,Cantarell,Fira Sans,Droid Sans,Helvetica Neue,sans-serif",
  fontWeight: "bold",
  fontSize: 16,
  margin: "0 0 8px 0",
}));

const SpanDescr = styled("span")(({ theme: { palette } }) => ({
  fontSize: 14,
  color: palette.text.secondary,
}));

function createData(
  image: string,
  name: string,
  descr: string,
  size: string | number,
  quantity: number,
  totalPrice: string,
) {
  return { image, name, descr, size, quantity, totalPrice };
}

const rows = [
  createData(
    "https://dynamic.zacdn.com/TIqU0jk90hPxnuO44NnNXO4B1AU=/fit-in/346x500/filters:quality(95):fill(ffffff)/http://static.sg.zalora.net/p/fila-4662-609589-1.jpg",
    "Henry T-Shirt",
    "White, Screen",
    "S",
    2,
    "$39.98",
  ),
  createData(
    "https://www.hybridoutfitters.com/wp-content/uploads/2019/11/147.jpg",
    "Stripe Tee",
    "ocean, stripe",
    "M",
    3,
    "$100",
  ),
  createData(
    "https://gloimg.zafcdn.com/zaful/pdm-product-pic/Clothing/2019/09/18/goods-first-img/1568766431491927776.jpg",
    "Sweater Hood",
    "Light Brown, Wool",
    "S",
    1,
    "$39.99",
  ),
  createData(
    "https://l.lnwfile.com/_resize_images/600/600/w1/nh/5z.jpg",
    "Jackboot",
    "Brown, Leather",
    10.5,
    1,
    "$69.99",
  ),
];

const DailyCart = () => {
  return (
    <Box pt={{ xs: 2, sm: 4, md: 6 }}>
      <TypographyHeading variant={"h1"} gutterBottom>
        Shopping Cart.
      </TypographyHeading>
      <TableContainer>
        <StyledTable aria-label="simple table">
          <TableHead>
            <TableRow>
              <TableCell>Product</TableCell>
              <TableCell>Size</TableCell>
              <TableCell>Quantity</TableCell>
              <TableCell>Total Price</TableCell>
              <TableCell>&nbsp;</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {rows.map((row) => (
              <TableRow key={row.name}>
                <TableCell component="th" scope="row">
                  <Box display={"flex"} alignItems={"center"}>
                    <Box width={80} height={80}>
                      <ImgImage alt={row.name} src={row.image} />
                    </Box>
                    <Box ml={2}>
                      <PName>{row.name}</PName>
                      <SpanDescr>{row.descr}</SpanDescr>
                    </Box>
                  </Box>
                </TableCell>
                <TableCell>
                  <DailySizeSelector>{row.size}</DailySizeSelector>
                </TableCell>
                <TableCell>
                  <DailyInteger>{row.quantity}</DailyInteger>
                </TableCell>
                <TableCell>{row.totalPrice}</TableCell>
                <TableCell>
                  <IconButton>
                    <Close />
                  </IconButton>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </StyledTable>
      </TableContainer>
    </Box>
  );
};

export default DailyCart;

"use client";
import React from "react";
import { styled } from "@mui/material/styles";
import Box from "@mui/material/Box";
import Typography from "@mui/material/Typography";
import Divider from "@mui/material/Divider";
