import TextField from "@mui/material/TextField";
import MenuItem from "@mui/material/MenuItem";

const BoxRoot = styled(Box)(() => ({
  display: "flex",
  flexDirection: "column",
  background: "linear-gradient(45deg, #191D29, #3c5981)",
  borderRadius: 12,
  height: "100%",
  overflow: "auto",

  "& *": {
    color: "#fff",
  },
}));

const TypographyHeading = styled(Typography)(() => ({
  fontWeight: 900,
  fontSize: "2.25rem",
}));

const StyledDivider = styled(Divider)(() => ({
  backgroundColor: "#fff",
  opacity: 0.12,
  margin: "24px 0",
}));

const TypographyLabel = styled(Typography)(() => ({
  fontSize: 12,
  fontWeight: "bold",
  marginBottom: 16,
  opacity: 0.87,
}));

const StyledTextField = styled(TextField)(() => ({
  "& label": {
    color: "#fff",
    opacity: 0.87,
    fontWeight: "bold",
  },
  "& .MuiInputBase-root": {
    color: "#fff",
  },
  "& .MuiOutlinedInput-notchedOutline": {
    borderColor: "rgba(255, 255, 255, 0.12)",
  },
  "&:hover": {
    "& .MuiOutlinedInput-notchedOutline": {
      borderColor: "rgba(255, 255, 255, 0.38)",
    },
  },
}));

const TextFieldSelect = styled(TextField)(() => ({
  "& label": {
    color: "#fff",
    opacity: 0.4,
  },
  "& .MuiInputBase-root": {
    color: "#fff",
  },
  "& .MuiOutlinedInput-notchedOutline": {
    borderColor: "rgba(255, 255, 255, 0.12)",
  },
  "&:hover": {
    "& .MuiOutlinedInput-notchedOutline": {
      borderColor: "rgba(255, 255, 255, 0.38)",
    },
  },
}));

const ButtonCheckoutBtn = styled(Button)(() => ({
  marginTop: "auto",
  borderRadius: 40,
  width: "100%",
}));

const DailyCheckout = () => {
  const styles = {
    button: {
      textTransform: "initial",
      minHeight: 48,
      borderRadius: 40,
      borderColor: "rgba(255, 255, 255, 0.12)",
      borderStyle: "solid",
      borderWidth: 1,
      width: "100%",
      color: "#fff",
      "&:hover": {
        backgroundColor: "rgba(255, 255, 255, 0.12)",
      },
    },
    buttonActive: {
      borderColor: "#fff",
    },
  } as const;
  return (
    <BoxRoot py={3} px={3.5}>
      <TypographyHeading variant={"h1"}>Payment Info.</TypographyHeading>
      <StyledDivider />
      <TypographyLabel>Payment Method:</TypographyLabel>
      <Grid container spacing={2}>
        <Grid size={6}>
          <Button
            startIcon={<CreditCard />}
            sx={{
              ...styles.button,
              ...styles.buttonActive,
            }}
          >
            Credit Card
          </Button>
        </Grid>
        <Grid size={6}>
          <Button
            sx={{
              ...styles.button,
              ...styles.buttonActive,
              fontSize: 20,
              textTransform: "initial",
              fontStyle: "italic",
              fontFamily:
                "-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,Oxygen,Ubuntu,Cantarell,Fira Sans,Droid Sans,Helvetica Neue,sans-serif",
              fontWeight: "bold",
              lineHeight: 1,
            }}
          >
            PayPal
          </Button>
        </Grid>
      </Grid>
      <StyledDivider />
      <StyledTextField
        fullWidth
        margin="dense"
        label={"Name On Card:"}
        value={"Siriwat Knp"}
      />
      <Box sx={{ height: 24, flex: "none" }} />
      <StyledTextField
        fullWidth
        margin="dense"
        label={"Card Number:"}
        value={"••••  ••••  ••••  1829"}
      />
      <Box sx={{ height: 24, flex: "none" }} />
      <Grid container spacing={3}>
        <Grid size={8}>
          <TypographyLabel>Expiration Date:</TypographyLabel>
          <Box>
            <Grid container spacing={2}>
              <Grid size={6}>
                <TextFieldSelect select fullWidth label={"MM"} defaultValue="">
                  {Array.from({ length: 12 }, (_, i) => {
                    const val = String(i + 1).padStart(2, "0");
                    return (
                      <MenuItem key={val} value={val}>
                        {val}
                      </MenuItem>
                    );
                  })}
                </TextFieldSelect>
              </Grid>
              <Grid size={6}>
                <TextFieldSelect
                  select
                  fullWidth
                  label={"YYYY"}
                  defaultValue=""
                >
                  {Array.from({ length: 10 }, (_, i) => {
                    const val = String(2025 + i);
                    return (
                      <MenuItem key={val} value={val}>
                        {val}
                      </MenuItem>
                    );
                  })}
                </TextFieldSelect>
              </Grid>
            </Grid>
          </Box>
        </Grid>
        <Grid size={4}>
          <TypographyLabel>CCV:</TypographyLabel>
          <StyledTextField
            fullWidth
            slotProps={{
              inputLabel: {
                shrink: true,
              },
            }}
            aria-label="CCV"
            placeholder={"XXX"}
          />
        </Grid>
      </Grid>
      <Box sx={{ height: 24, flex: "none" }} />
      <ButtonCheckoutBtn color={"primary"} variant={"contained"}>
        Check Out.
      </ButtonCheckoutBtn>
    </BoxRoot>
  );
};

export default DailyCheckout;

